{
  "plan": [
    {
      "tool": "iam.check_permission",
      "arguments": {
        "resource": "license_utilization_metrics",
        "action": "read",
        "context": "SAM seat utilization analysis for Salesforce"
      },
      "depends_on": []
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "query": "SELECT cf.publisher, cf.product, cf.license_id, SUM(cf.daily_active_seats) AS total_active_seats, COUNT(DISTINCT cf.user_id) AS distinct_users, SUM(cf.amount_usd) AS total_spend_usd, AVG(cf.daily_active_seats) AS avg_daily_active_seats, MAX(cf.daily_active_seats) AS max_daily_active_seats, MIN(cf.daily_active_seats) AS min_daily_active_seats, COUNT(cf.event_id) AS event_count FROM consumption_facts cf WHERE cf.publisher ILIKE '%salesforce%' GROUP BY cf.publisher, cf.product, cf.license_id ORDER BY total_spend_usd DESC"
      },
      "depends_on": [1]
    },
    {
      "tool": "sql.snowflake.query",
      "arguments": {
        "query": "SELECT lc.license_id, lc.product, lc.publisher, lc.licensed_seats, lc.assigned_seats, lc.contract_start_date, lc.contract_end_date, lc.annual_cost_usd, lc.cost_per_seat_usd, (lc.licensed_seats - lc.assigned_seats) AS unassigned_seats, ROUND((lc.assigned_seats::FLOAT / NULLIF(lc.licensed_seats, 0)) * 100, 2) AS assignment_rate_pct FROM license_contracts lc WHERE lc.publisher ILIKE '%salesforce%' AND lc.contract_end_date >= CURRENT_DATE ORDER BY lc.annual_cost_usd DESC"
      },
      "depends_on": [1]
    },
    {
      "tool": "sql.postgres.query",
